css:
.loader {
  color: var(--loader-color, #db2777);
  height: 54px;
  aspect-ratio: 1;
  border: 3px solid var(--loader-secondary-color, #f9a8d4);
  position: relative;
}
.loader:before {
  content: "";
  position: absolute;
  width: 30%;
  aspect-ratio: 1;
  border-radius: 50%;
  background: var(--loader-color, #db2777);
  animation: 
    l7-0 .49s infinite alternate linear -.11s,
    l7-1 .71s infinite alternate linear -.23s;
}
@keyframes l7-0 {
  0%,5%  {bottom: 0%}
  95%,to {bottom: 70%}
}
@keyframes l7-1 {
  0%,5%  {left: 0%}
  95%,to {left: 70%}
}
